  1→import { useRef, useCallback, useEffect, useState } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { usePlanClipboardController } from '@/clipboard/usePlanClipboardController';
  5→import { normalizeRectBounds } from '@/clipboard/planClipboard';
  6→import { getFloorElevation } from '@/domain/floorModels';
  7→import { useEditorTool } from '@/editor/useEditorTool';
  8→import { MIN_ZOOM, MAX_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  9→import { formatSurveyorBearing, pointsToSurveyorBearing } from '@/geometry/bearing';
 10→import { TOOLS } from '@/editor/tools';
 11→import ClipboardPreviewLayer from './ClipboardPreviewLayer';
 12→import CompassOverlay from '@/ui/CompassOverlay';
 13→import GridRenderer from './GridRenderer';
 14→import SlabRenderer from './SlabRenderer';
 15→import WallRenderer from './WallRenderer';
 16→import BeamRenderer from './BeamRenderer';
 17→import StairRenderer from './StairRenderer';
 18→import DoorRenderer from './DoorRenderer';
 19→import WindowRenderer from './WindowRenderer';
 20→import RoomRenderer from './RoomRenderer';
 21→import AnnotationRenderer from './AnnotationRenderer';
 22→import ElevationRenderer from './ElevationRenderer';
 23→import SectionRenderer from './SectionRenderer';
 24→import SelectionOverlay from './SelectionOverlay';
 25→import DimensionPreview from './DimensionPreview';
 26→import WallPreview from './WallPreview';
 27→import LandingRenderer from './LandingRenderer';
 28→import LandingPreview from './LandingPreview';
 29→import ColumnRenderer from './ColumnRenderer';
 30→import ColumnPreview from './ColumnPreview';
 31→import FixtureDefs from './FixtureDefs';
 32→import FixtureRenderer from './FixtureRenderer';
 33→import FixturePreview from './FixturePreview';
 34→import BeamPreview from './BeamPreview';
 35→import StairPreview from './StairPreview';
 36→import SlabPreview from './SlabPreview';
 37→import DoorWindowPreview from './DoorWindowPreview';
 38→import RoomPreview from './RoomPreview';
 39→import SectionCutRenderer from './SectionCutRenderer';
 40→import SectionCutPreview from './SectionCutPreview';
 41→import RailingRenderer from './RailingRenderer';
 42→import RailingPreview from './RailingPreview';
 43→import RegionSelectionOverlay from './RegionSelectionOverlay';
 44→import { CenterViewIcon, ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
 45→import { isTypingTarget } from '@/utils/keyboard';
 46→import styles from './SvgCanvas.module.css';
 47→
 48→function screenToModel(screenX, screenY, viewport, svgRect) {
 49→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 50→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 51→  return { x, y };
 52→}
 53→
 54→export default function SvgCanvas() {
 55→  const svgRef = useRef(null);
 56→  const isPanning = useRef(false);
 57→  const lastPanPos = useRef({ x: 0, y: 0 });
 58→  const spaceHeld = useRef(false);
 59→  const cursorPosRef = useRef({ x: 0, y: 0 });
 60→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 61→
 62→  const { project, dispatch, getFloor } = useProject();
 63→  const editor = useEditor();
 64→  const {
 65→    activeTool, selectedId, selectedType, toolState,
 66→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 67→    regionSelection, pastePreview, maximizedPanel,
 68→    dispatch: editorDispatch,
 69→  } = editor;
 70→
 71→  const floor = getFloor(activeFloorId);
 72→  const {
 73→    copySelection,
 74→    cutSelection,
 75→    beginPaste,
 76→    updatePastePreview,
 77→    cancelPaste,
 78→    placePaste,
 79→    previewContent,
 80→  } = usePlanClipboardController();
 81→
 82→  const tool = useEditorTool({
 83→    activeTool,
 84→    dispatch,
 85→    editorDispatch,
 86→    project,
 87→    getFloor,
 88→    activeFloorId,
 89→    viewport,
 90→    snapEnabled,
 91→    selectedId,
 92→    selectedType,
 93→    toolState,
 94→    viewMode,
 95→  });
 96→
 97→  const getModelPos = useCallback((e) => {
 98→    const rect = svgRef.current.getBoundingClientRect();
 99→    return screenToModel(e.clientX, e.clientY, viewport, rect);
100→  }, [viewport]);
101→
102→  const handleMouseDown = useCallback((e) => {
103→    // Middle mouse or space+left for pan
104→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
105→      isPanning.current = true;
106→      lastPanPos.current = { x: e.clientX, y: e.clientY };
107→      e.preventDefault();
108→      return;
109→    }
110→
111→    const modelPos = getModelPos(e);
112→    if (pastePreview?.active && e.button === 0) {
113→      placePaste(modelPos);
114→      return;
115→    }
116→    tool.onMouseDown(modelPos, e);
117→  }, [getModelPos, pastePreview, placePaste, tool]);
118→
119→  const handleMouseMove = useCallback((e) => {
120→    if (isPanning.current) {
121→      const dx = e.clientX - lastPanPos.current.x;
122→      const dy = e.clientY - lastPanPos.current.y;
123→      editorDispatch({ type: 'PAN', dx, dy });
124→      lastPanPos.current = { x: e.clientX, y: e.clientY };
125→      return;
126→    }
127→
128→    const modelPos = getModelPos(e);
129→    cursorPosRef.current = modelPos;
130→    setCursorPos(modelPos);
131→    if (pastePreview?.active) {
132→      updatePastePreview(modelPos);
133→      return;
134→    }
135→    tool.onMouseMove(modelPos, e);
136→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
137→
138→  const handleMouseUp = useCallback((e) => {
139→    if (isPanning.current) {
140→      isPanning.current = false;
141→      return;
142→    }
143→    if (pastePreview?.active) return;
144→    const modelPos = getModelPos(e);
145→    tool.onMouseUp(modelPos, e);
146→  }, [getModelPos, pastePreview, tool]);
147→
148→  const handleDoubleClick = useCallback((e) => {
149→    if (pastePreview?.active) return;
150→    const modelPos = getModelPos(e);
151→    tool.onDoubleClick(modelPos, e);
152→  }, [getModelPos, pastePreview, tool]);
153→
154→  const handleWheel = useCallback((e) => {
155→    e.preventDefault();
156→    const rect = svgRef.current.getBoundingClientRect();
157→    const mouseX = e.clientX - rect.left;
158→    const mouseY = e.clientY - rect.top;
159→
160→    const direction = e.deltaY < 0 ? 1 : -1;
161→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
162→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
163→
164→    // Zoom centered on cursor
165→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
166→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
167→
168→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
169→  }, [viewport, editorDispatch]);
170→
171→  const handleResetCenterPoint = useCallback(() => {
172→    const rect = svgRef.current?.getBoundingClientRect();
173→    if (!rect) return;
174→
175→    editorDispatch({
176→      type: 'SET_VIEWPORT',
177→      viewport: {
178→        ...viewport,
179→        panX: rect.width / 2,
180→        panY: rect.height / 2,
181→      },
182→    });
183→  }, [editorDispatch, viewport]);
184→
185→  useEffect(() => {
186→    if (!statusMessage) return undefined;
187→
188→    const timer = window.setTimeout(() => {
189→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
190→    }, 2500);
191→
192→    return () => window.clearTimeout(timer);
193→  }, [statusMessage, editorDispatch]);
194→
195→  useEffect(() => {
196→    const handleKeyDown = (e) => {
197→      if (isTypingTarget(e.target)) return;
198→
199→      if (e.key === ' ') {
200→        spaceHeld.current = true;
201→        e.preventDefault();
202→      }
203→
204→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan') {
205→        const key = e.key.toLowerCase();
206→        if (key === 'c') {
207→          e.preventDefault();
208→          copySelection();
209→          return;
210→        }
211→        if (key === 'x') {
212→          e.preventDefault();
213→          cutSelection();
214→          return;
215→        }
216→        if (key === 'v') {
217→          e.preventDefault();
218→          beginPaste(cursorPosRef.current);
219→          return;
220→        }
221→      }
222→
223→      if (e.key === 'Escape' && pastePreview?.active) {
224→        e.preventDefault();
225→        cancelPaste();
226→        return;
227→      }
228→
229→      // Tool shortcuts
230→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
231→        switch (e.key.toLowerCase()) {
232→          case 'v':
233→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
234→            return;
235→          case 'm':
236→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
237→            return;
238→          case 'w':
239→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
240→            return;
241→          case 'b':
242→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
243→            return;
244→          case 't':
245→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
246→            return;
247→          case 'q':
248→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
249→            return;
250→          case 's':
251→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
252→            return;
253→          case 'r':
254→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
255→            return;
256→          case 'd':
257→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
258→            return;
259→          case 'n':
260→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
261→            return;
262→          case 'c':
263→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
264→            return;
265→          case 'l':
266→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
267→            return;
268→          case 'h':
269→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.RAILING });
270→            return;
271→          case 'f':
272→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
273→            editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType: 'kitchenTop', previewRotation: 0 } });
274→            return;
275→        }
276→      }
277→
278→      tool.onKeyDown(e);
279→    };
280→
281→    const handleKeyUp = (e) => {
282→      if (isTypingTarget(e.target)) return;
283→
284→      if (e.key === ' ') {
285→        spaceHeld.current = false;
286→      }
287→    };
288→
289→    window.addEventListener('keydown', handleKeyDown);
290→    window.addEventListener('keyup', handleKeyUp);
291→    return () => {
292→      window.removeEventListener('keydown', handleKeyDown);
293→      window.removeEventListener('keyup', handleKeyUp);
294→    };
295→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
296→
297→  // Prevent default context menu on SVG
298→  useEffect(() => {
299→    const svg = svgRef.current;
300→    if (!svg) return;
301→    const prevent = (e) => e.preventDefault();
302→    svg.addEventListener('contextmenu', prevent);
303→    svg.addEventListener('wheel', handleWheel, { passive: false });
304→    return () => {
305→      svg.removeEventListener('contextmenu', prevent);
306→      svg.removeEventListener('wheel', handleWheel);
307→    };
308→  }, [handleWheel]);
309→
310→  const cursor = spaceHeld.current ? 'grab' : pastePreview?.active ? 'copy' : tool.getCursor();
311→  const zoomPercent = Math.round(viewport.zoom * 1000);
312→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
313→  const isCanvasMaximized = maximizedPanel === 'canvas';
314→  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
315→    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
316→    : null;
317→  const selectionCount = regionSelection?.objectCount || 0;
318→  const liveWallBearing = activeTool === TOOLS.WALL && toolState.start && toolState.preview
319→    ? formatSurveyorBearing(pointsToSurveyorBearing(toolState.start, toolState.preview))
320→    : null;
321→
322→  return (
323→    <div className={styles.canvasContainer}>
324→      <CompassOverlay className={styles.compassDock} />
325→      <svg
326→        ref={svgRef}
327→        className={styles.svg}
328→        style={{ cursor }}
329→        onMouseDown={handleMouseDown}
330→        onMouseMove={handleMouseMove}
331→        onMouseUp={handleMouseUp}
332→        onDoubleClick={handleDoubleClick}
333→      >
334→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
335→          {viewMode === 'plan' && showGrid && <GridRenderer />}
336→          {viewMode === 'plan' && showGrid && (
337→            <rect
338→              x={-100000} y={-100000}
339→              width={200000} height={200000}
340→              fill="url(#grid-major)"
341→              style={{ pointerEvents: 'none' }}
342→            />
343→          )}
344→          {floor && (
345→            viewMode === 'plan' ? (
346→              <>
347→                <FixtureDefs />
348→                {(floor.slabs || []).map(slab => (
349→                  <SlabRenderer key={slab.id} slab={slab} selectedId={selectedId} />
350→                ))}
351→                <RoomRenderer rooms={floor.rooms} selectedId={selectedId} />
352→                <RoomPreview toolState={toolState} activeTool={activeTool} />
353→                <WallRenderer walls={floor.walls} columns={floor.columns || []} />
354→                <BeamRenderer beams={floor.beams || []} columns={floor.columns || []} />
355→                <StairRenderer stairs={floor.stairs || []} />
356→                <LandingRenderer landings={floor.landings || []} />
357→                <RailingRenderer railings={floor.railings || []} />
358→                <ColumnRenderer columns={floor.columns || []} />
359→                <FixtureRenderer fixtures={floor.fixtures || []} />
360→                <DoorRenderer doors={floor.doors} walls={floor.walls} />
361→                <WindowRenderer windows={floor.windows} walls={floor.walls} />
362→                {(floor.sectionCuts || []).map(sc => (
363→                  <SectionCutRenderer key={sc.id} sectionCut={sc} selectedId={selectedId} />
364→                ))}
365→                <AnnotationRenderer floor={floor} />
366→                <ClipboardPreviewLayer content={previewContent} />
367→                <RegionSelectionOverlay
368→                  marqueeBounds={marqueeBounds}
369→                  selectionBounds={regionSelection?.bounds || null}
370→                />
371→                <SelectionOverlay
372→                  selectedId={selectedId}
373→                  selectedType={selectedType}
374→                  floor={floor}
375→                  zoom={viewport.zoom}
376→                />
377→                <DimensionPreview toolState={toolState} activeTool={activeTool} />
378→                <WallPreview toolState={toolState} activeTool={activeTool} />
379→                <SlabPreview toolState={toolState} activeTool={activeTool} />
380→                <BeamPreview
381→                  toolState={toolState}
382→                  activeTool={activeTool}
383→                  columns={floor.columns || []}
384→                  floorLevel={getFloorElevation(floor)}
385→                />
386→                <StairPreview
387→                  toolState={toolState}
388→                  activeTool={activeTool}
389→                  floorId={floor.id}
390→                />
391→                <DoorWindowPreview
392→                  toolState={toolState}
393→                  activeTool={activeTool}
394→                  walls={floor.walls}
395→                />
396→                <SectionCutPreview toolState={toolState} activeTool={activeTool} />
397→                <RailingPreview toolState={toolState} activeTool={activeTool} />
398→                <ColumnPreview toolState={toolState} activeTool={activeTool} />
399→                <LandingPreview toolState={toolState} activeTool={activeTool} />
400→                <FixturePreview toolState={toolState} activeTool={activeTool} />
401→              </>
402→            ) : viewMode === 'section_view' ? (
403→              <SectionRenderer
404→                project={project}
405→                floor={floor}
406→                activeSectionCutId={activeSectionCutId}
407→              />
408→            ) : (
409→              <ElevationRenderer
410→                project={project}
411→                floor={floor}
412→                viewMode={viewMode}
413→                selectedId={selectedId}
414→                selectedType={selectedType}
415→              />
416→            )
417→          )}
418→        </g>
419→      </svg>
420→      <div className={styles.overlayControls}>
421→        <button
422→          type="button"
423→          className={styles.overlayBtn}
424→          onClick={handleResetCenterPoint}
425→          title="Reset center point"
426→          aria-label="Reset center point"
427→        >
428→          <CenterViewIcon />
429→        </button>
430→        <button
431→          type="button"
432→          className={styles.overlayBtn}
433→          onClick={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'canvas' })}
434→          title={isCanvasMaximized ? 'Restore split view' : 'Maximize canvas'}
435→          aria-label={isCanvasMaximized ? 'Restore split view' : 'Maximize canvas'}
436→        >
437→          {isCanvasMaximized ? <CollapseIcon /> : <ExpandIcon />}
438→        </button>
439→      </div>
440→      <div className={styles.statusBar}>
441→        <span>X: {Math.round(cursorPos.x)} mm</span>
442→        <span>Y: {Math.round(cursorPos.y)} mm</span>
443→        <span>Zoom: {zoomPercent}%</span>
444→        <span>View: {viewMode}</span>
445→        <span>Tool: {displayedTool}</span>
446→        {liveWallBearing && <span>Bearing: {liveWallBearing}</span>}
447→        {selectionCount > 0 && <span>Selection: {selectionCount} objects</span>}
448→        {pastePreview?.active && <span>Paste: click to place</span>}
449→        {statusMessage && <span className={styles.statusMessage}>{statusMessage}</span>}
450→      </div>
451→    </div>
452→  );
453→}
