 142→async function renderSvgToCanvas(svgElement, dpi = DEFAULT_PNG_DPI, imageMap = new Map()) {
 143→  const width = Number(svgElement.getAttribute('width')) || 100;
 144→  const height = Number(svgElement.getAttribute('height')) || 100;
 145→  const scale = getCanvasScaleFromDpi(dpi);
 146→  const canvas = document.createElement('canvas');
 147→  canvas.width = Math.max(1, Math.round(width * scale));
 148→  canvas.height = Math.max(1, Math.round(height * scale));
 149→  const context = canvas.getContext('2d');
 150→  context.fillStyle = '#ffffff';
 151→  context.fillRect(0, 0, canvas.width, canvas.height);
 152→  context.scale(scale, scale);
 153→  [...svgElement.children].forEach((child) => drawElementToCanvas(context, child, imageMap));
 154→  return { canvas };
 155→}
