 224→    Math.abs(matrix.a - 1) < 1e-8
 225→    && Math.abs(matrix.b) < 1e-8
 226→    && Math.abs(matrix.c) < 1e-8
 227→    && Math.abs(matrix.d - 1) < 1e-8
 228→    && Math.abs(matrix.e) < 1e-8
