 297→function computeStyle(element) {
 298→  const style = window.getComputedStyle(element);
 299→  const fill = parseColor(style.fill);
 300→  const stroke = parseColor(style.stroke);
 301→  const strokeWidth = Number.parseFloat(style.strokeWidth) || 0;
 302→  const lineCap = style.strokeLinecap || 'butt';
 303→  const lineJoin = style.strokeLinejoin || 'miter';
 304→  const dashArray = parseNumberList(style.strokeDasharray || '');
 305→  const fontSize = Number.parseFloat(style.fontSize) || 12;
 306→  const opacity = Number.parseFloat(style.opacity || '1') || 1;
 307→  const fillOpacity = fill ? opacity * (Number.parseFloat(style.fillOpacity || '1') || 1) : 0;
 308→  const strokeOpacity = stroke ? opacity * (Number.parseFloat(style.strokeOpacity || '1') || 1) : 0;
 309→
 310→  return {
 311→    fill,
 312→    stroke,
 313→    strokeWidth,
 314→    lineCap,
 315→    lineJoin,
 316→    dashArray,
 317→    fontSize,
 318→    fontFamily: style.fontFamily || 'Arial',
 319→    fontWeight: style.fontWeight || '400',
 320→    textAnchor: style.textAnchor || 'start',
 321→    dominantBaseline: style.dominantBaseline || 'auto',
 322→    fillOpacity,
 323→    strokeOpacity,
 324→  };
 325→}
