1031→function buildVectorPdfFromSvg(svgElement, paperSize, imageMap = new Map()) {
1032→  const paper = getPaperPreset(paperSize);
1033→  const pageWidthPt = paper.width * MM_TO_PT;
1034→  const pageHeightPt = paper.height * MM_TO_PT;
1035→  const builder = new PdfBuilder(pageWidthPt, pageHeightPt);
1036→
1037→  builder.write('q');
1038→  builder.write(`${fmt(MM_TO_PT)} 0 0 ${fmt(-MM_TO_PT)} 0 ${fmt(pageHeightPt)} cm`);
1039→  [...svgElement.children].forEach((child) => walkElement(builder, child, imageMap));
1040→  builder.write('Q');
1041→
1042→  return builder.finish();
1043→}
