  1→import * as THREE from 'three';
  2→
  3→const SELECTED_SURFACE_COLOR = new THREE.Color(0xcdeedd);
  4→const SELECTED_EMISSIVE_COLOR = new THREE.Color(0x0f8f74);
  5→const SELECTED_OUTLINE_COLOR = new THREE.Color(0x0f8f74);
  6→
  7→function planPointToWorld(point, elevation = 0) {
  8→  return new THREE.Vector3(point.x, elevation, point.y);
  9→}
 10→
 11→function planAngleToWorldRotation(angle = 0) {
 12→  return -angle;
 13→}
 14→
 15→function createShape(outline) {
 16→  const shape = new THREE.Shape();
 17→  outline.forEach((point, index) => {
 18→    if (index === 0) {
 19→      // Flip plan Y here so the rotated extrusion preserves the blueprint's handedness.
 20→      shape.moveTo(point.x, -point.y);
 21→      return;
 22→    }
 23→    shape.lineTo(point.x, -point.y);
 24→  });
 25→  shape.closePath();
 26→  return shape;
 27→}
 28→
 29→function applySelectedSurfaceStyle(material) {
 30→  if (material.color) {
 31→    material.color.lerp(SELECTED_SURFACE_COLOR, 0.36);
 32→  }
 33→  if ('emissive' in material && material.emissive) {
 34→    material.emissive.copy(SELECTED_EMISSIVE_COLOR);
 35→    material.emissiveIntensity = material.transparent ? 0.12 : 0.22;
 36→  }
 37→  if (material.transparent) {
 38→    material.opacity = Math.min(0.82, Math.max(material.opacity ?? 1, 0.58));
 39→  }
 40→}
 41→
 42→function createMeshMaterial(materialPalette, materialKey, isSelected) {
 43→  const material = materialPalette[materialKey].clone();
 44→  if (isSelected) applySelectedSurfaceStyle(material);
 45→  return material;
 46→}
 47→
 48→function createOutlineMaterial(materialPalette, isSelected) {
 49→  const material = materialPalette.outline.clone();
 50→  if (isSelected) {
 51→    material.color.copy(SELECTED_OUTLINE_COLOR);
 52→    material.opacity = 1;
 53→  }
 54→  return material;
 55→}
 56→
 57→function addOutline(object3d, materialPalette, isSelected) {
 58→  if (!object3d.geometry) return;
 59→  const edges = new THREE.EdgesGeometry(object3d.geometry, 20);
 60→  const outline = new THREE.LineSegments(edges, createOutlineMaterial(materialPalette, isSelected));
 61→  object3d.add(outline);
 62→}
 63→
 64→function createPrismObject(descriptor, materialPalette, isSelected) {
 65→  const geometry = new THREE.ExtrudeGeometry(createShape(descriptor.outline), {
 66→    depth: descriptor.height,
 67→    bevelEnabled: false,
 68→    curveSegments: 1,
 69→    steps: 1,
 70→  });
 71→
 72→  geometry.rotateX(-Math.PI / 2);
 73→  geometry.translate(0, descriptor.baseElevation, 0);
 74→
 75→  const mesh = new THREE.Mesh(geometry, createMeshMaterial(materialPalette, descriptor.materialKey, isSelected));
 76→  mesh.castShadow = true;
 77→  mesh.receiveShadow = true;
 78→  addOutline(mesh, materialPalette, isSelected);
 79→  return mesh;
 80→}
 81→
 82→function createBoxObject(descriptor, materialPalette, isSelected) {
 83→  const geometry = new THREE.BoxGeometry(
 84→    Math.max(descriptor.size.x, 1),
 85→    Math.max(descriptor.size.y, 1),
 86→    Math.max(descriptor.size.z, 1)
 87→  );
 88→  const mesh = new THREE.Mesh(geometry, createMeshMaterial(materialPalette, descriptor.materialKey, isSelected));
 89→  const center = planPointToWorld(
 90→    descriptor.center,
 91→    descriptor.baseElevation + descriptor.size.y / 2
 92→  );
 93→  mesh.position.copy(center);
 94→  mesh.rotation.y = planAngleToWorldRotation(descriptor.rotation);
 95→  mesh.castShadow = true;
 96→  mesh.receiveShadow = true;
 97→  addOutline(mesh, materialPalette, isSelected);
 98→  return mesh;
 99→}
100→
101→function createStairObject(descriptor, materialPalette, isSelected) {
102→  const group = new THREE.Group();
103→  const risers = Math.max(1, descriptor.numberOfRisers || 1);
104→
105→  for (let index = 0; index < risers; index += 1) {
106→    const geometry = new THREE.BoxGeometry(
107→      Math.max(descriptor.treadDepth, 1),
108→      Math.max(descriptor.riserHeight, 1),
109→      Math.max(descriptor.width, 1)
110→    );
111→    const step = new THREE.Mesh(geometry, createMeshMaterial(materialPalette, descriptor.materialKey, isSelected));
112→    step.position.set(
113→      descriptor.treadDepth * (index + 0.5),
114→      descriptor.riserHeight * (index + 0.5),
115→      0
116→    );
117→    step.castShadow = true;
118→    step.receiveShadow = true;
119→    addOutline(step, materialPalette, isSelected);
120→    group.add(step);
121→  }
122→
123→  group.position.copy(planPointToWorld(descriptor.startPoint, descriptor.baseElevation));
124→  group.rotation.y = planAngleToWorldRotation(descriptor.angle * Math.PI / 180);
125→  return group;
126→}
127→
128→function createWindowObject(descriptor, materialPalette, isSelected) {
129→  const group = new THREE.Group();
130→  const { x: width, y: height, z: depth } = descriptor.size;
131→
132→  const frameWidth = Math.max(40, Math.min(width, height) * 0.06);
133→  const glassThickness = Math.max(depth * 0.15, 10);
134→  const mullionWidth = frameWidth * 0.5;
135→
136→  const frameMaterial = createMeshMaterial(materialPalette, 'windowFrame', isSelected);
137→  const glassMaterial = createMeshMaterial(materialPalette, 'window', isSelected);
138→
139→  // Frame rails
140→  const frameRails = [
141→    // top
142→    { sx: width, sy: frameWidth, sz: depth, px: 0, py: (height - frameWidth) / 2, pz: 0 },
143→    // bottom
144→    { sx: width, sy: frameWidth, sz: depth, px: 0, py: -(height - frameWidth) / 2, pz: 0 },
145→    // left
146→    { sx: frameWidth, sy: height - frameWidth * 2, sz: depth, px: -(width - frameWidth) / 2, py: 0, pz: 0 },
147→    // right
148→    { sx: frameWidth, sy: height - frameWidth * 2, sz: depth, px: (width - frameWidth) / 2, py: 0, pz: 0 },
149→  ];
150→
151→  for (const rail of frameRails) {
152→    const geo = new THREE.BoxGeometry(
153→      Math.max(rail.sx, 1), Math.max(rail.sy, 1), Math.max(rail.sz, 1)
154→    );
155→    const mesh = new THREE.Mesh(geo, frameMaterial);
156→    mesh.position.set(rail.px, rail.py, rail.pz);
157→    mesh.castShadow = true;
158→    mesh.receiveShadow = true;
159→    addOutline(mesh, materialPalette, isSelected);
160→    group.add(mesh);
161→  }
162→
163→  // Glass pane (no outline — dark edges look wrong on glass)
164→  const innerW = width - frameWidth * 2;
165→  const innerH = height - frameWidth * 2;
166→  const glassGeo = new THREE.BoxGeometry(
167→    Math.max(innerW, 1), Math.max(innerH, 1), Math.max(glassThickness, 1)
168→  );
169→  const glassMesh = new THREE.Mesh(glassGeo, glassMaterial);
170→  glassMesh.castShadow = false;
171→  glassMesh.receiveShadow = true;
172→  group.add(glassMesh);
173→
174→  // Type-specific mullions
175→  const windowType = descriptor.windowType || 'standard';
176→  const mullions = [];
177→
178→  if (windowType === 'standard') {
179→    // 2 horizontal bars at 1/3 and 2/3 height
180→    const thirdH = innerH / 3;
181→    mullions.push(
182→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: -thirdH / 2 + innerH / 6, pz: 0 },
183→    );
184→    mullions.push(
185→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: thirdH / 2 - innerH / 6, pz: 0 },
186→    );
187→    // Positions: at -innerH/6 and +innerH/6 from center = 1/3 and 2/3 of inner height
188→    mullions.length = 0; // clear and redo cleanly
189→    mullions.push(
190→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: -innerH / 2 + innerH / 3, pz: 0 },
191→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: -innerH / 2 + (innerH * 2) / 3, pz: 0 },
192→    );
193→  } else if (windowType === 'casement') {
194→    // 1 vertical center bar
195→    mullions.push(
196→      { sx: mullionWidth, sy: innerH, sz: depth, px: 0, py: 0, pz: 0 },
197→    );
198→  } else if (windowType === 'awning') {
199→    // 1 horizontal bar at ~30% from top
200→    mullions.push(
201→      { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: innerH / 2 - innerH * 0.3, pz: 0 },
202→    );
203→  } else if (windowType === 'jalousie') {
204→    // 5 evenly-spaced horizontal bars
205→    for (let i = 1; i <= 5; i++) {
206→      const y = -innerH / 2 + (innerH * i) / 6;
207→      mullions.push(
208→        { sx: innerW, sy: mullionWidth, sz: depth, px: 0, py: y, pz: 0 },
209→      );
210→    }
211→  }
212→  // 'fixed' — no mullions
213→
214→  for (const m of mullions) {
215→    const geo = new THREE.BoxGeometry(
216→      Math.max(m.sx, 1), Math.max(m.sy, 1), Math.max(m.sz, 1)
217→    );
218→    const mesh = new THREE.Mesh(geo, frameMaterial);
219→    mesh.position.set(m.px, m.py, m.pz);
220→    mesh.castShadow = true;
221→    mesh.receiveShadow = true;
222→    addOutline(mesh, materialPalette, isSelected);
223→    group.add(mesh);
224→  }
225→
226→  // Position and rotate the group
227→  const center = planPointToWorld(
228→    descriptor.center,
229→    descriptor.baseElevation + height / 2
230→  );
231→  group.position.copy(center);
232→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
233→
234→  return group;
235→}
