 13→const EPSILON = 1e-6;
 14→
 15→function clamp(value, min, max) {
 16→  return Math.max(min, Math.min(max, value));
 17→}
 18→
 19→function uniqueSortedValues(values = []) {
 20→  const sorted = [...values].sort((a, b) => a - b);
 21→  return sorted.filter((value, index) => (
 22→    index === 0 || Math.abs(value - sorted[index - 1]) > 1e-4
 23→  ));
 24→}
 25→
 26→function intervalFromValues(values, maxLength) {
 27→  if (!values.length) return null;
 28→  const clamped = values
 29→    .map((value) => clamp(value, 0, maxLength))
 30→    .filter((value) => value >= -EPSILON && value <= maxLength + EPSILON);
 31→  if (!clamped.length) return null;
 32→
 33→  const left = Math.min(...clamped);
 34→  const right = Math.max(...clamped);
 35→  if (right - left < EPSILON) return null;
 36→  return { left, right };
 37→}
 38→
 39→function projectPolygon(sectionCut, polygon = []) {
 40→  return polygon.map((point) => projectPointToSectionCut(sectionCut, point));
 41→}
 42→
 43→function polygonCutInterval(sectionCut, polygon = []) {
 44→  if (polygon.length < 3) return null;
 45→
 46→  const values = [];
 47→  for (let index = 0; index < polygon.length; index += 1) {
 48→    const start = polygon[index];
 49→    const end = polygon[(index + 1) % polygon.length];
 50→    const hit = segmentIntersection(sectionCut.startPoint, sectionCut.endPoint, start, end);
 51→    if (hit) {
 52→      values.push(projectPointToSectionCut(sectionCut, hit).along);
 53→    }
 54→  }
 55→
 56→  if (pointInPolygon(sectionCut.startPoint, polygon)) values.push(0);
 57→  if (pointInPolygon(sectionCut.endPoint, polygon)) values.push(sectionCutLength(sectionCut));
 58→
 59→  return intervalFromValues(uniqueSortedValues(values), sectionCutLength(sectionCut));
 60→}
