 62→function polygonProjectionInfo(sectionCut, polygon = [], depth) {
 63→  if (polygon.length < 3) return null;
 64→  const projected = projectPolygon(sectionCut, polygon);
 65→  const alongs = projected.map((entry) => entry.along);
 66→  const offsets = projected.map((entry) => entry.offset);
 67→  const minOffset = Math.min(...offsets);
 68→  const maxOffset = Math.max(...offsets);
 69→
 70→  if (maxOffset < -EPSILON || minOffset > depth + EPSILON) return null;
 71→
 72→  return {
 73→    interval: intervalFromValues(alongs, sectionCutLength(sectionCut)),
 74→    depth: offsets.reduce((sum, value) => sum + Math.max(0, value), 0) / Math.max(1, offsets.length),
 75→    minOffset,
 76→    maxOffset,
 77→  };
 78→}
